/**
 * Pure mapping: BFF DTO → frontend Approval model.
 */

import { Approval, ApprovalStats } from '../../models/Approval';
import { PaginatedResponse } from '../../models/common';
import {
  BffApprovalDto,
  BffApprovalStatsDto,
  BffApprovalPagedDto,
} from './responseModel';

export const mapBffApproval = (dto: BffApprovalDto): Approval => ({
  id:                   dto.id,
  title:                dto.title,
  description:          dto.description,
  type:                 dto.type as Approval['type'],
  priority:             dto.priority as Approval['priority'],
  status:               dto.status as Approval['status'],
  requesterId:          dto.requesterId,
  requesterName:        dto.requesterName,
  requesterRole:        '',
  requesterAvatar:      dto.requesterAvatar,
  requestedAt:          dto.requestedAt || '',
  decidedAt:            dto.decidedAt || undefined,
  decisionNote:         dto.decisionNote,
  delegation:           dto.delegation,
  attachments:          dto.attachments,
  createdAt:            dto.createdAt || '',
  updatedAt:            dto.updatedAt || '',
  currentApproverLevel: 1,
  totalApprovalLevels:  1,
  isEscalated:          false,
});

export const mapBffApprovalStats = (dto: BffApprovalStatsDto): ApprovalStats => {
  const decisions = dto.totalApproved + dto.totalRejected;
  return {
    pending:       dto.totalPending,
    approvedToday: dto.totalApproved,
    rejectedToday: dto.totalRejected,
    approvalRate:  decisions > 0 ? Math.round((dto.totalApproved / decisions) * 100) : 0,
    overdue:       dto.overdue,
  };
};

export const mapBffApprovalPaged = (dto: BffApprovalPagedDto): PaginatedResponse<Approval> => ({
  items:      dto.items.map(mapBffApproval),
  total:      dto.total,
  page:       dto.page,
  pageSize:   dto.pageSize,
  totalPages: dto.totalPages,
});
