import { createSlice, PayloadAction, createAsyncThunk } from '@reduxjs/toolkit';
import { User } from '../../models/User';
import { authService } from '../../services/authService';

function dispatchAuthTokenChanged(token: string | null): void {
  window.dispatchEvent(new CustomEvent('linm:auth:token-changed', { detail: { token } }));
}

interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
  loading: boolean;
  /** True while logout is in-flight (used to show spinner in UI) */
  logoutLoading: boolean;
  error: string | null;
  requirePasswordChange: boolean;
}

const initialState: AuthState = {
  user: null,
  isAuthenticated: false,
  loading: false,
  logoutLoading: false,
  error: null,
  requirePasswordChange: false,
};

// Load persisted auth state from localStorage
const loadPersistedAuth = (): Partial<AuthState> => {
  try {
    const token = localStorage.getItem('auth_token');
    const userStr = localStorage.getItem('auth_user');
    
    if (token && userStr) {
      const user = JSON.parse(userStr);
      return {
        user,
        isAuthenticated: true,
        requirePasswordChange: user.requirePasswordChange ?? false,
      };
    }
  } catch (error) {
    console.error('Failed to load persisted auth:', error);
  }
  
  return {};
};

// Apply persisted state to initial state
const persistedAuth = loadPersistedAuth();
Object.assign(initialState, persistedAuth);

// Async thunks
export const login = createAsyncThunk(
  'auth/login',
  async ({ username, password, activeCompanyId }: { username: string; password: string; activeCompanyId?: string }) => {
    const response = await authService.login(username, password, activeCompanyId);
    
    // Persist to localStorage
    localStorage.setItem('auth_token', response.token);
    localStorage.setItem('auth_refresh_token', response.refreshToken);
    localStorage.setItem('auth_user', JSON.stringify(response.user));

    dispatchAuthTokenChanged(response.token);
    
    return response;
  }
);

export const logout = createAsyncThunk('auth/logout', async () => {
  // 1. Notify backend FIRST while the token is still in localStorage.
  //    This prevents the 401-interceptor in api.ts from running a pointless
  //    refresh attempt and triggering a window.location.href redirect that
  //    would bypass our Redux cleanup (visible in incognito / private tabs).
  //    Network failures are non-blocking — always clean up regardless.
  try { await authService.logout(); } catch (err) {
    console.error('[auth] Logout backend call failed (force clean-up applied):', err);
  }

  // 2. Clear frontend state after the backend call so the token is still
  //    valid for the duration of step 1.
  localStorage.removeItem('auth_token');
  localStorage.removeItem('auth_refresh_token');
  localStorage.removeItem('auth_user');

  dispatchAuthTokenChanged(null);
});

export const getCurrentUser = createAsyncThunk(
  'auth/getCurrentUser',
  async () => {
    const response = await authService.getCurrentUser();
    return response;
  }
);

export const switchCompany = createAsyncThunk(
  'auth/switchCompany',
  async (companyId: string) => {
    const response = await authService.switchCompany(companyId);

    // Persist updated tokens/user
    localStorage.setItem('auth_token', response.token);
    localStorage.setItem('auth_refresh_token', response.refreshToken);
    localStorage.setItem('auth_user', JSON.stringify(response.user));

    dispatchAuthTokenChanged(response.token);

    return response;
  }
);

const authSlice = createSlice({
  name: 'auth',
  initialState,
  reducers: {
    clearError: (state) => {
      state.error = null;
    },
    setUser: (state, action: PayloadAction<User>) => {
      state.user = action.payload;
      state.isAuthenticated = true;
    },
    clearRequirePasswordChange: (state) => {
      state.requirePasswordChange = false;
      if (state.user) {
        state.user.requirePasswordChange = false;
        // Persist updated user to localStorage
        localStorage.setItem('auth_user', JSON.stringify(state.user));
      }
    },
    /**
     * Called after a silent token refresh when the server returns updated user data.
     * Applies any changes (e.g. defaultMenuUrl) to the Redux store immediately.
     */
    updateUserFromRefresh: (state, action: PayloadAction<User>) => {
      if (state.user) {
        state.user = { ...state.user, ...action.payload };
        localStorage.setItem('auth_user', JSON.stringify(state.user));
      }
    },
  },
  extraReducers: (builder) => {
    builder
      // Login
      .addCase(login.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(login.fulfilled, (state, action) => {
        state.loading = false;
        state.user = action.payload.user;
        state.isAuthenticated = true;
        state.error = null;
        state.requirePasswordChange = action.payload.user.requirePasswordChange ?? false;
      })
      .addCase(login.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Đăng nhập thất bại';
        state.isAuthenticated = false;
        state.user = null;
        state.requirePasswordChange = false;
      })
      // Logout
      .addCase(logout.pending, (state) => {
        state.logoutLoading = true;
      })
      .addCase(logout.fulfilled, (state) => {
        state.logoutLoading = false;
        state.user = null;
        state.isAuthenticated = false;
        state.error = null;
        state.requirePasswordChange = false;
      })
      .addCase(logout.rejected, (state) => {
        // Force cleanup even when the thunk itself rejects (should not happen,
        // but guard defensively)
        state.logoutLoading = false;
        state.user = null;
        state.isAuthenticated = false;
        state.requirePasswordChange = false;
      })
      // Get current user
      .addCase(getCurrentUser.fulfilled, (state, action) => {
        state.user = action.payload;
        state.isAuthenticated = true;
      })
      // Switch company
      .addCase(switchCompany.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(switchCompany.fulfilled, (state, action) => {
        state.loading = false;
        state.user = action.payload.user;
        state.isAuthenticated = true;
        state.error = null;
      })
      .addCase(switchCompany.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Chuyển đổi công ty thất bại';
      });
  },
});

export const { clearError, setUser, clearRequirePasswordChange, updateUserFromRefresh } = authSlice.actions;
export default authSlice.reducer;