/**
 * Real BFF API calls for Approval endpoints.
 */

import { Approval, ApprovalFilters, ApprovalStats } from '../../models/Approval';
import { PaginatedResponse, UUID } from '../../models/common';
import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import {
  BffApprovalDto,
  BffApprovalStatsDto,
  BffApprovalPagedDto,
  BffBulkActionResultDto,
} from './responseModel';
import { mapBffApproval, mapBffApprovalStats, mapBffApprovalPaged } from './mapper';
import {
  ApproveApprovalRequest,
  RejectApprovalRequest,
  RequestChangesRequest,
  DelegateApprovalRequest,
  BulkApprovalRequest,
} from './requestModel';

export const approvalEndpoint = {
  getApprovals: async (
    filters?: ApprovalFilters,
    page = 1,
    pageSize = 20
  ): Promise<PaginatedResponse<Approval>> => {
    const qs = new URLSearchParams({
      page: page.toString(),
      pageSize: pageSize.toString(),
      ...(filters?.status     && { status:      filters.status }),
      ...(filters?.type       && { type:         filters.type }),
      ...(filters?.priority   && { priority:     filters.priority }),
      ...(filters?.requesterId && { requesterId: filters.requesterId }),
      ...(filters?.dateFrom   && { dateFrom:     filters.dateFrom }),
      ...(filters?.dateTo     && { dateTo:       filters.dateTo }),
      ...(filters?.searchQuery && { search:      filters.searchQuery }),
    });
    const res = await apiClient.get<BffResponse<BffApprovalPagedDto>>(`/approvals?${qs}`);
    return mapBffApprovalPaged(unwrap(res));
  },

  getPendingApprovals: async (): Promise<Approval[]> => {
    const res = await apiClient.get<BffResponse<BffApprovalDto[]>>('/approvals/pending');
    return unwrap(res).map(mapBffApproval);
  },

  getApprovalStats: async (): Promise<ApprovalStats> => {
    const res = await apiClient.get<BffResponse<BffApprovalStatsDto>>('/approvals/stats');
    return mapBffApprovalStats(unwrap(res));
  },

  getApprovalById: async (id: UUID): Promise<Approval> => {
    const res = await apiClient.get<BffResponse<BffApprovalDto>>(`/approvals/${id}`);
    return mapBffApproval(unwrap(res));
  },

  approveApproval: async (req: ApproveApprovalRequest): Promise<Approval> => {
    const res = await apiClient.post<BffResponse<BffApprovalDto>>(
      `/approvals/${req.approvalId}/approve`,
      { note: req.note }
    );
    return mapBffApproval(unwrap(res));
  },

  rejectApproval: async (req: RejectApprovalRequest): Promise<Approval> => {
    const res = await apiClient.post<BffResponse<BffApprovalDto>>(
      `/approvals/${req.approvalId}/reject`,
      { reason: req.reason }
    );
    return mapBffApproval(unwrap(res));
  },

  requestChanges: async (req: RequestChangesRequest): Promise<Approval> => {
    const res = await apiClient.post<BffResponse<BffApprovalDto>>(
      `/approvals/${req.approvalId}/request-changes`,
      { changes: req.changes }
    );
    return mapBffApproval(unwrap(res));
  },

  delegateApproval: async (req: DelegateApprovalRequest): Promise<Approval> => {
    const res = await apiClient.post<BffResponse<BffApprovalDto>>(
      `/approvals/${req.approvalId}/delegate`,
      {
        delegateToId:   req.delegateToId,
        delegateToName: req.delegateToName,
        reason:         req.reason,
        timeframe:      req.timeframe,
      }
    );
    return mapBffApproval(unwrap(res));
  },

  bulkAction: async (
    req: BulkApprovalRequest
  ): Promise<{ success: boolean; processed: number }> => {
    const res = await apiClient.post<BffResponse<BffBulkActionResultDto>>(
      '/approvals/bulk',
      req
    );
    return unwrap(res);
  },
};
