/**
 * PackageConfigPage
 * Admin page for configuring package-linked features:
 *   Tab 1: "Menu" — CRUD for menu items (label, url, defaultUrl, icon, parent, permissions)
 *   Tab 2: "Endpoint API" — CRUD for backend endpoint configs + package assignments
 * Uses getAdminInit() for initial dropdown data (permissions + packages).
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavTitle } from '@linm-soft/common-components';
import { adminService } from '../../services/admin';
import type {
  BffMenuItemDto,
  BffEndpointConfigDto,
  BffPermissionDto,
  BffFeaturePackageDto,
} from '../../services/admin/responseModel';
import { Slideout } from '../../components/common/Slideout';
import { Tabs } from '../../components/common/Tabs';
import { useResponsive } from '../../hooks/useResponsive';
import { useAppToast } from '../../hooks/useAppToast';
import { useAppSelector } from '../../store/hooks';
import styles from './PackageConfigPage.module.css';

// ─────────────────────────────────────────────────────────────────────────────
// Types
// ─────────────────────────────────────────────────────────────────────────────

interface MenuItemFormData {
  code:        string;
  label:       string;
  path:        string;
  defaultUrl:  string;
  icon:        string;
  parentId:    string;
  orderIndex:  string;
  isGroup:     boolean;
  isActive:    boolean;
  permissionIds: string[];
}

interface EndpointFormData {
  endpointCode: string;
  endpointName: string;
  serviceName:  string;
  httpMethod:   string;
  routePattern: string;
  module:       string;
  description:  string;
  isActive:     boolean;
  packageIds:   string[];
}

const emptyMenuForm: MenuItemFormData = {
  code: '', label: '', path: '', defaultUrl: '', icon: '',
  parentId: '', orderIndex: '0', isGroup: false, isActive: true, permissionIds: [],
};

const emptyEndpointForm: EndpointFormData = {
  endpointCode: '', endpointName: '', serviceName: 'WebAppService',
  httpMethod: 'GET', routePattern: '', module: '', description: '',
  isActive: true, packageIds: [],
};

const HTTP_METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'];

// ─────────────────────────────────────────────────────────────────────────────
// Main component
// ─────────────────────────────────────────────────────────────────────────────

const PackageConfigPage: React.FC = () => {
  useNavTitle('Cấu hình gói tính năng');
  const { isMobile, isTablet } = useResponsive();
  const toast = useAppToast();
  const slideoutWidth = isMobile ? '100%' : isTablet ? '520px' : '660px';
  const currentUser = useAppSelector((state) => state.auth.user);
  const currentUsername = currentUser?.username ?? 'admin';

  const [activeTab, setActiveTab] = useState('menu');

  // ── Shared dropdown data (loaded once via getAdminInit) ────────────────────
  const [permissions, setPermissions] = useState<BffPermissionDto[]>([]);
  const [packages, setPackages]       = useState<BffFeaturePackageDto[]>([]);

  // ── Menu Items state ───────────────────────────────────────────────────────
  const [menuItems, setMenuItems]           = useState<BffMenuItemDto[]>([]);
  const [menuLoading, setMenuLoading]       = useState(true);
  const [menuSearch, setMenuSearch]         = useState('');
  const [menuFormOpen, setMenuFormOpen]     = useState(false);
  const [editingMenu, setEditingMenu]       = useState<BffMenuItemDto | null>(null);
  const [menuForm, setMenuForm]             = useState<MenuItemFormData>(emptyMenuForm);
  const [menuFormError, setMenuFormError]   = useState('');
  const [menuSaving, setMenuSaving]         = useState(false);
  const [deleteMenuId, setDeleteMenuId]     = useState<string | null>(null);
  const [menuDeleting, setMenuDeleting]     = useState(false);

  // ── Endpoint Config state ─────────────────────────────────────────────────
  const [endpoints, setEndpoints]           = useState<BffEndpointConfigDto[]>([]);
  const [epLoading, setEpLoading]           = useState(true);
  const [epSearch, setEpSearch]             = useState('');
  const [epFormOpen, setEpFormOpen]         = useState(false);
  const [editingEp, setEditingEp]           = useState<BffEndpointConfigDto | null>(null);
  const [epForm, setEpForm]                 = useState<EndpointFormData>(emptyEndpointForm);
  const [epFormError, setEpFormError]       = useState('');
  const [epSaving, setEpSaving]             = useState(false);
  const [deleteEpId, setDeleteEpId]         = useState<string | null>(null);
  const [epDeleting, setEpDeleting]         = useState(false);

  // ── Cancel refs (React 18 StrictMode pattern) ──────────────────────────────
  const initCancelRef = useRef(false);
  const menuCancelRef = useRef(false);
  const epCancelRef   = useRef(false);

  // ── Load shared dropdown data ──────────────────────────────────────────────
  const loadInit = useCallback(async () => {
    initCancelRef.current = false;
    try {
      const data = await adminService.getAdminInit();
      if (initCancelRef.current) return;
      setPermissions(data.permissions ?? []);
      setPackages((data.packages ?? []).filter(p => p.isActive));
    } catch {
      if (!initCancelRef.current) toast.error('Không thể tải dữ liệu cấu hình');
    } finally {

    }
  }, []); // eslint-disable-line

  // ── Load menu items ────────────────────────────────────────────────────────
  const loadMenuItems = useCallback(async () => {
    menuCancelRef.current = false;
    setMenuLoading(true);
    try {
      const data = await adminService.getMenuItems();
      if (menuCancelRef.current) return;
      // Flatten the tree for table display
      const flat: BffMenuItemDto[] = [];
      const flatten = (items: BffMenuItemDto[]) => {
        for (const item of items) {
          flat.push(item);
          if (item.children?.length) flatten(item.children);
        }
      };
      flatten(data);
      setMenuItems(flat);
    } catch {
      if (!menuCancelRef.current) toast.error('Không thể tải danh sách menu');
    } finally {
      if (!menuCancelRef.current) setMenuLoading(false);
    }
  }, []); // eslint-disable-line

  // ── Load endpoint configs ──────────────────────────────────────────────────
  const loadEndpoints = useCallback(async () => {
    epCancelRef.current = false;
    setEpLoading(true);
    try {
      const data = await adminService.getEndpointConfigs();
      if (epCancelRef.current) return;
      setEndpoints(data);
    } catch {
      if (!epCancelRef.current) toast.error('Không thể tải danh sách endpoint');
    } finally {
      if (!epCancelRef.current) setEpLoading(false);
    }
  }, []); // eslint-disable-line

  useEffect(() => {
    const t = setTimeout(() => {
      loadInit();
      loadMenuItems();
      loadEndpoints();
    }, 0);
    return () => {
      clearTimeout(t);
      initCancelRef.current = true;
      menuCancelRef.current = true;
      epCancelRef.current   = true;
    };
  }, [loadInit, loadMenuItems, loadEndpoints]);

  // ── Menu item form helpers ─────────────────────────────────────────────────
  const openMenuCreate = () => {
    setEditingMenu(null);
    setMenuForm(emptyMenuForm);
    setMenuFormError('');
    setMenuFormOpen(true);
  };

  const openMenuEdit = (item: BffMenuItemDto) => {
    setEditingMenu(item);
    setMenuForm({
      code:          item.code,
      label:         item.label,
      path:          item.path ?? '',
      defaultUrl:    item.defaultUrl ?? '',
      icon:          item.icon ?? '',
      parentId:      item.parentId ?? '',
      orderIndex:    String(item.orderIndex),
      isGroup:       item.isGroup,
      isActive:      item.isActive,
      permissionIds: item.requiredPermissionCodes.map(code =>
        permissions.find(p => p.code === code)?.id ?? '',
      ).filter(Boolean),
    });
    setMenuFormError('');
    setMenuFormOpen(true);
  };

  const saveMenuItem = async () => {
    if (!menuForm.label.trim()) { setMenuFormError('Vui lòng nhập tên menu'); return; }
    if (!editingMenu && !menuForm.code.trim()) { setMenuFormError('Vui lòng nhập mã menu'); return; }
    setMenuSaving(true);
    setMenuFormError('');
    try {
      if (editingMenu) {
        await adminService.updateMenuItem(editingMenu.id, {
          label:      menuForm.label,
          path:       menuForm.path || null,
          defaultUrl: menuForm.defaultUrl || null,
          icon:       menuForm.icon || null,
          parentId:   menuForm.parentId || null,
          orderIndex: parseInt(menuForm.orderIndex) || 0,
          isActive:   menuForm.isActive,
          isGroup:    menuForm.isGroup,
        });
        // Update permissions separately if changed
        await adminService.assignPermissionsToMenuItem(editingMenu.id, {
          permissionIds: menuForm.permissionIds,
        });
        toast.success('Cập nhật menu thành công');
      } else {
        await adminService.createMenuItem({
          code:          menuForm.code,
          label:         menuForm.label,
          path:          menuForm.path || null,
          defaultUrl:    menuForm.defaultUrl || null,
          icon:          menuForm.icon || null,
          parentId:      menuForm.parentId || null,
          orderIndex:    parseInt(menuForm.orderIndex) || 0,
          isGroup:       menuForm.isGroup,
          permissionIds: menuForm.permissionIds,
        });
        toast.success('Tạo menu thành công');
      }
      setMenuFormOpen(false);
      await loadMenuItems();
    } catch (err: any) {
      setMenuFormError(err?.message ?? 'Lỗi khi lưu menu');
    } finally {
      setMenuSaving(false);
    }
  };

  const confirmDeleteMenu = async () => {
    if (!deleteMenuId) return;
    setMenuDeleting(true);
    try {
      await adminService.deleteMenuItem(deleteMenuId);
      toast.success('Đã xóa menu');
      setDeleteMenuId(null);
      await loadMenuItems();
    } catch {
      toast.error('Không thể xóa menu');
    } finally {
      setMenuDeleting(false);
    }
  };

  // ── Endpoint form helpers ──────────────────────────────────────────────────
  const openEpCreate = () => {
    setEditingEp(null);
    setEpForm(emptyEndpointForm);
    setEpFormError('');
    setEpFormOpen(true);
  };

  const openEpEdit = (ep: BffEndpointConfigDto) => {
    setEditingEp(ep);
    setEpForm({
      endpointCode: ep.endpointCode,
      endpointName: ep.endpointName,
      serviceName:  ep.serviceName,
      httpMethod:   ep.httpMethod,
      routePattern: ep.routePattern ?? '',
      module:       ep.module,
      description:  ep.description ?? '',
      isActive:     ep.isActive,
      packageIds:   ep.allowedPackageCodes.map(code =>
        packages.find(p => p.code === code)?.id ?? '',
      ).filter(Boolean),
    });
    setEpFormError('');
    setEpFormOpen(true);
  };

  const saveEndpoint = async () => {
    if (!epForm.endpointName.trim()) { setEpFormError('Vui lòng nhập tên endpoint'); return; }
    if (!editingEp && !epForm.endpointCode.trim()) { setEpFormError('Vui lòng nhập mã endpoint'); return; }
    if (!epForm.module.trim()) { setEpFormError('Vui lòng nhập module'); return; }
    setEpSaving(true);
    setEpFormError('');
    try {
      if (editingEp) {
        await adminService.updateEndpointConfig(editingEp.id, {
          endpointName: epForm.endpointName,
          serviceName:  epForm.serviceName,
          httpMethod:   epForm.httpMethod,
          routePattern: epForm.routePattern || null,
          module:       epForm.module,
          description:  epForm.description || null,
          isActive:     epForm.isActive,
        });
        await adminService.assignPackagesToEndpoint(editingEp.id, {
          packageIds: epForm.packageIds,
          assignedBy: currentUsername,
        });
        toast.success('Cập nhật endpoint thành công');
      } else {
        await adminService.createEndpointConfig({
          endpointCode: epForm.endpointCode,
          endpointName: epForm.endpointName,
          serviceName:  epForm.serviceName,
          httpMethod:   epForm.httpMethod,
          routePattern: epForm.routePattern || null,
          module:       epForm.module,
          description:  epForm.description || null,
          packageIds:   epForm.packageIds,
        });
        toast.success('Tạo endpoint thành công');
      }
      setEpFormOpen(false);
      await loadEndpoints();
    } catch (err: any) {
      setEpFormError(err?.message ?? 'Lỗi khi lưu endpoint');
    } finally {
      setEpSaving(false);
    }
  };

  const confirmDeleteEp = async () => {
    if (!deleteEpId) return;
    setEpDeleting(true);
    try {
      await adminService.deleteEndpointConfig(deleteEpId);
      toast.success('Đã xóa endpoint');
      setDeleteEpId(null);
      await loadEndpoints();
    } catch {
      toast.error('Không thể xóa endpoint');
    } finally {
      setEpDeleting(false);
    }
  };

  // ── Filtered lists ─────────────────────────────────────────────────────────
  const filteredMenu = menuItems.filter(m => {
    if (!menuSearch) return true;
    const q = menuSearch.toLowerCase();
    return m.label.toLowerCase().includes(q) || m.code.toLowerCase().includes(q) ||
           (m.path ?? '').toLowerCase().includes(q);
  });

  const filteredEndpoints = endpoints.filter(e => {
    if (!epSearch) return true;
    const q = epSearch.toLowerCase();
    return e.endpointName.toLowerCase().includes(q) ||
           e.endpointCode.toLowerCase().includes(q) ||
           e.serviceName.toLowerCase().includes(q) ||
           e.module.toLowerCase().includes(q);
  });

  // ── Render ─────────────────────────────────────────────────────────────────
  const tabs = [
    { id: 'menu',     label: 'Menu điều hướng' },
    { id: 'endpoint', label: 'Endpoint API' },
  ];

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <h1 className={styles.pageTitle}>Cấu hình gói tính năng</h1>
        <p className={styles.pageSubtitle}>Quản lý menu giao diện và phân quyền endpoint backend</p>
      </div>

      <Tabs tabs={tabs} activeTab={activeTab} onTabChange={setActiveTab} />

      {/* ── Tab: Menu Items ─────────────────────────────────────── */}
      {activeTab === 'menu' && (
        <div className={styles.tabContent}>
          <div className={styles.tableToolbar}>
            <input
              className={styles.searchInput}
              placeholder="Tìm theo tên, mã, đường dẫn..."
              value={menuSearch}
              onChange={e => setMenuSearch(e.target.value)}
            />
            <button className={styles.btnPrimary} onClick={openMenuCreate}>
              + Thêm menu
            </button>
          </div>

          {menuLoading ? (
            <div className={styles.loading}>Đang tải...</div>
          ) : (
            <div className={styles.tableWrapper}>
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th>Mã</th>
                    <th>Tên menu</th>
                    <th>Đường dẫn</th>
                    <th>URL mặc định</th>
                    <th>Nhóm cha</th>
                    <th>Thứ tự</th>
                    <th>Trạng thái</th>
                    <th>Quyền</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {filteredMenu.length === 0 ? (
                    <tr><td colSpan={9} className={styles.emptyRow}>Không có dữ liệu</td></tr>
                  ) : filteredMenu.map(item => (
                    <tr key={item.id}>
                      <td><code className={styles.codeTag}>{item.code}</code></td>
                      <td>
                        {item.isGroup && <span className={styles.badge}>Nhóm</span>}
                        {item.label}
                      </td>
                      <td className={styles.pathCell}>{item.path ?? '—'}</td>
                      <td className={styles.pathCell}>{item.defaultUrl ?? '—'}</td>
                      <td>{item.parentId
                        ? menuItems.find(m => m.id === item.parentId)?.label ?? item.parentId.slice(0,8)
                        : '—'}
                      </td>
                      <td>{item.orderIndex}</td>
                      <td>
                        <span className={item.isActive ? styles.badgeActive : styles.badgeInactive}>
                          {item.isActive ? 'Hoạt động' : 'Ẩn'}
                        </span>
                      </td>
                      <td>
                        <span className={styles.permCount}>
                          {item.requiredPermissionCodes.length > 0
                            ? `${item.requiredPermissionCodes.length} quyền`
                            : 'Công khai'}
                        </span>
                      </td>
                      <td className={styles.actionCell}>
                        <button className={styles.btnEdit} onClick={() => openMenuEdit(item)}>Sửa</button>
                        <button className={styles.btnDelete} onClick={() => setDeleteMenuId(item.id)}>Xóa</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Confirm delete menu */}
          {deleteMenuId && (
            <div className={styles.overlay} onClick={() => setDeleteMenuId(null)}>
              <div className={styles.confirmDialog} onClick={e => e.stopPropagation()}>
                <p>Bạn có chắc muốn xóa menu <strong>{menuItems.find(m=>m.id===deleteMenuId)?.label}</strong>?</p>
                <div className={styles.confirmActions}>
                  <button className={styles.btnCancel} onClick={() => setDeleteMenuId(null)}>Hủy</button>
                  <button className={styles.btnDanger} onClick={confirmDeleteMenu} disabled={menuDeleting}>
                    {menuDeleting ? 'Đang xóa...' : 'Xóa'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── Tab: Endpoint Configs ─────────────────────────────────── */}
      {activeTab === 'endpoint' && (
        <div className={styles.tabContent}>
          <div className={styles.tableToolbar}>
            <input
              className={styles.searchInput}
              placeholder="Tìm theo tên, mã, service, module..."
              value={epSearch}
              onChange={e => setEpSearch(e.target.value)}
            />
            <button className={styles.btnPrimary} onClick={openEpCreate}>
              + Thêm endpoint
            </button>
          </div>

          {epLoading ? (
            <div className={styles.loading}>Đang tải...</div>
          ) : (
            <div className={styles.tableWrapper}>
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th>Mã endpoint</th>
                    <th>Tên</th>
                    <th>Service</th>
                    <th>Method</th>
                    <th>Module</th>
                    <th>Route</th>
                    <th>Gói được phép</th>
                    <th>Trạng thái</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {filteredEndpoints.length === 0 ? (
                    <tr><td colSpan={9} className={styles.emptyRow}>Không có dữ liệu</td></tr>
                  ) : filteredEndpoints.map(ep => (
                    <tr key={ep.id}>
                      <td><code className={styles.codeTag}>{ep.endpointCode}</code></td>
                      <td>{ep.endpointName}</td>
                      <td><span className={styles.serviceTag}>{ep.serviceName}</span></td>
                      <td>
                        <span className={`${styles.methodTag} ${styles[`method${ep.httpMethod}`]}`}>
                          {ep.httpMethod}
                        </span>
                      </td>
                      <td>{ep.module}</td>
                      <td className={styles.pathCell}>{ep.routePattern ?? '—'}</td>
                      <td>
                        {ep.allowedPackageCodes.length > 0
                          ? ep.allowedPackageCodes.join(', ')
                          : <span className={styles.noPackage}>Chưa gán</span>}
                      </td>
                      <td>
                        <span className={ep.isActive ? styles.badgeActive : styles.badgeInactive}>
                          {ep.isActive ? 'Hoạt động' : 'Tắt'}
                        </span>
                      </td>
                      <td className={styles.actionCell}>
                        <button className={styles.btnEdit} onClick={() => openEpEdit(ep)}>Sửa</button>
                        <button className={styles.btnDelete} onClick={() => setDeleteEpId(ep.id)}>Xóa</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Confirm delete endpoint */}
          {deleteEpId && (
            <div className={styles.overlay} onClick={() => setDeleteEpId(null)}>
              <div className={styles.confirmDialog} onClick={e => e.stopPropagation()}>
                <p>Xóa endpoint <strong>{endpoints.find(e=>e.id===deleteEpId)?.endpointCode}</strong>?</p>
                <div className={styles.confirmActions}>
                  <button className={styles.btnCancel} onClick={() => setDeleteEpId(null)}>Hủy</button>
                  <button className={styles.btnDanger} onClick={confirmDeleteEp} disabled={epDeleting}>
                    {epDeleting ? 'Đang xóa...' : 'Xóa'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── Slideout: Menu Item Form ────────────────────────────────── */}
      <Slideout
        isOpen={menuFormOpen}
        onClose={() => setMenuFormOpen(false)}
        title={editingMenu ? 'Chỉnh sửa menu' : 'Thêm menu mới'}
        width={slideoutWidth}
      >
        <div className={styles.form}>
          {!editingMenu && (
            <div className={styles.formGroup}>
              <label className={styles.label}>Mã menu <span className={styles.required}>*</span></label>
              <input
                className={styles.input}
                value={menuForm.code}
                onChange={e => setMenuForm(f => ({ ...f, code: e.target.value }))}
                placeholder="vd: admin.users, ticket.list"
              />
              <span className={styles.hint}>Chỉ chữ thường, dấu chấm, không dấu cách</span>
            </div>
          )}

          <div className={styles.formGroup}>
            <label className={styles.label}>Tên hiển thị <span className={styles.required}>*</span></label>
            <input
              className={styles.input}
              value={menuForm.label}
              onChange={e => setMenuForm(f => ({ ...f, label: e.target.value }))}
              placeholder="vd: Quản lý người dùng"
            />
          </div>

          <div className={styles.formRow}>
            <div className={styles.formGroup}>
              <label className={styles.label}>Đường dẫn (path)</label>
              <input
                className={styles.input}
                value={menuForm.path}
                onChange={e => setMenuForm(f => ({ ...f, path: e.target.value }))}
                placeholder="vd: /admin/users"
              />
            </div>
            <div className={styles.formGroup}>
              <label className={styles.label}>URL mặc định</label>
              <input
                className={styles.input}
                value={menuForm.defaultUrl}
                onChange={e => setMenuForm(f => ({ ...f, defaultUrl: e.target.value }))}
                placeholder="vd: /admin/users?status=active"
              />
              <span className={styles.hint}>URL landing khi người dùng mở section này</span>
            </div>
          </div>

          <div className={styles.formRow}>
            <div className={styles.formGroup}>
              <label className={styles.label}>Icon</label>
              <input
                className={styles.input}
                value={menuForm.icon}
                onChange={e => setMenuForm(f => ({ ...f, icon: e.target.value }))}
                placeholder="vd: users, ticket, settings"
              />
            </div>
            <div className={styles.formGroup}>
              <label className={styles.label}>Thứ tự</label>
              <input
                className={styles.input}
                type="number"
                value={menuForm.orderIndex}
                onChange={e => setMenuForm(f => ({ ...f, orderIndex: e.target.value }))}
              />
            </div>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.label}>Menu cha</label>
            <select
              className={styles.select}
              value={menuForm.parentId}
              onChange={e => setMenuForm(f => ({ ...f, parentId: e.target.value }))}
            >
              <option value="">— Không có (top-level) —</option>
              {menuItems.filter(m => m.isGroup).map(m => (
                <option key={m.id} value={m.id}>{m.label} ({m.code})</option>
              ))}
            </select>
          </div>

          <div className={styles.formCheckRow}>
            <label className={styles.checkLabel}>
              <input
                type="checkbox"
                checked={menuForm.isGroup}
                onChange={e => setMenuForm(f => ({ ...f, isGroup: e.target.checked }))}
              />
              <span>Đây là nhóm menu (section header)</span>
            </label>
            {editingMenu && (
              <label className={styles.checkLabel}>
                <input
                  type="checkbox"
                  checked={menuForm.isActive}
                  onChange={e => setMenuForm(f => ({ ...f, isActive: e.target.checked }))}
                />
                <span>Hiển thị</span>
              </label>
            )}
          </div>

          <div className={styles.formGroup}>
            <label className={styles.label}>Yêu cầu quyền (để trống = công khai)</label>
            <div className={styles.permissionList}>
              {permissions.map(p => (
                <label key={p.id} className={styles.checkLabel}>
                  <input
                    type="checkbox"
                    checked={menuForm.permissionIds.includes(p.id)}
                    onChange={e => setMenuForm(f => ({
                      ...f,
                      permissionIds: e.target.checked
                        ? [...f.permissionIds, p.id]
                        : f.permissionIds.filter(id => id !== p.id),
                    }))}
                  />
                  <span><strong>{p.module}</strong>: {p.name} <code>({p.code})</code></span>
                </label>
              ))}
            </div>
          </div>

          {menuFormError && <p className={styles.error}>{menuFormError}</p>}

          <div className={styles.formActions}>
            <button className={styles.btnCancel} onClick={() => setMenuFormOpen(false)}>Hủy</button>
            <button className={styles.btnPrimary} onClick={saveMenuItem} disabled={menuSaving}>
              {menuSaving ? 'Đang lưu...' : editingMenu ? 'Cập nhật' : 'Tạo mới'}
            </button>
          </div>
        </div>
      </Slideout>

      {/* ── Slideout: Endpoint Config Form ─────────────────────────── */}
      <Slideout
        isOpen={epFormOpen}
        onClose={() => setEpFormOpen(false)}
        title={editingEp ? 'Chỉnh sửa endpoint' : 'Thêm endpoint mới'}
        width={slideoutWidth}
      >
        <div className={styles.form}>
          {!editingEp && (
            <div className={styles.formGroup}>
              <label className={styles.label}>Mã endpoint <span className={styles.required}>*</span></label>
              <input
                className={styles.input}
                value={epForm.endpointCode}
                onChange={e => setEpForm(f => ({ ...f, endpointCode: e.target.value }))}
                placeholder="vd: ticket:create, incident:read"
              />
              <span className={styles.hint}>Dạng module:action, chữ thường</span>
            </div>
          )}

          <div className={styles.formGroup}>
            <label className={styles.label}>Tên endpoint <span className={styles.required}>*</span></label>
            <input
              className={styles.input}
              value={epForm.endpointName}
              onChange={e => setEpForm(f => ({ ...f, endpointName: e.target.value }))}
              placeholder="vd: Tạo phiếu yêu cầu"
            />
          </div>

          <div className={styles.formRow}>
            <div className={styles.formGroup}>
              <label className={styles.label}>Service</label>
              <select
                className={styles.select}
                value={epForm.serviceName}
                onChange={e => setEpForm(f => ({ ...f, serviceName: e.target.value }))}
              >
                <option value="WebAppService">WebAppService</option>
                <option value="AuthenticationService">AuthenticationService</option>
                <option value="NotificationService">NotificationService</option>
              </select>
            </div>
            <div className={styles.formGroup}>
              <label className={styles.label}>HTTP Method</label>
              <select
                className={styles.select}
                value={epForm.httpMethod}
                onChange={e => setEpForm(f => ({ ...f, httpMethod: e.target.value }))}
              >
                {HTTP_METHODS.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>
          </div>

          <div className={styles.formRow}>
            <div className={styles.formGroup}>
              <label className={styles.label}>Module <span className={styles.required}>*</span></label>
              <input
                className={styles.input}
                value={epForm.module}
                onChange={e => setEpForm(f => ({ ...f, module: e.target.value }))}
                placeholder="vd: Ticket, Incident, Admin"
              />
            </div>
            <div className={styles.formGroup}>
              <label className={styles.label}>Route pattern</label>
              <input
                className={styles.input}
                value={epForm.routePattern}
                onChange={e => setEpForm(f => ({ ...f, routePattern: e.target.value }))}
                placeholder="vd: api/v1/tickets"
              />
            </div>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.label}>Mô tả</label>
            <textarea
              className={styles.textarea}
              value={epForm.description}
              onChange={e => setEpForm(f => ({ ...f, description: e.target.value }))}
              rows={2}
            />
          </div>

          {editingEp && (
            <div className={styles.formCheckRow}>
              <label className={styles.checkLabel}>
                <input
                  type="checkbox"
                  checked={epForm.isActive}
                  onChange={e => setEpForm(f => ({ ...f, isActive: e.target.checked }))}
                />
                <span>Đang hoạt động (enforce permission check)</span>
              </label>
            </div>
          )}

          <div className={styles.formGroup}>
            <label className={styles.label}>Gói tính năng được phép truy cập</label>
            <div className={styles.permissionList}>
              {packages.map(p => (
                <label key={p.id} className={styles.checkLabel}>
                  <input
                    type="checkbox"
                    checked={epForm.packageIds.includes(p.id)}
                    onChange={e => setEpForm(f => ({
                      ...f,
                      packageIds: e.target.checked
                        ? [...f.packageIds, p.id]
                        : f.packageIds.filter(id => id !== p.id),
                    }))}
                  />
                  <span><strong>{p.code}</strong>: {p.name}</span>
                </label>
              ))}
            </div>
          </div>

          {epFormError && <p className={styles.error}>{epFormError}</p>}

          <div className={styles.formActions}>
            <button className={styles.btnCancel} onClick={() => setEpFormOpen(false)}>Hủy</button>
            <button className={styles.btnPrimary} onClick={saveEndpoint} disabled={epSaving}>
              {epSaving ? 'Đang lưu...' : editingEp ? 'Cập nhật' : 'Tạo mới'}
            </button>
          </div>
        </div>
      </Slideout>
    </div>
  );
};

export default PackageConfigPage;
