/**
 * Pure mapping functions: BFF DTO → frontend User model.
 * No side effects, no API calls, no mock data.
 */

import { User, UserRole } from '../../models/User';
import { BffUserDto } from './responseModel';

export const mapBffUser = (dto: BffUserDto): User => ({
  id:             dto.id,
  username:       dto.username,
  email:          dto.email,
  firstName:      dto.firstName,
  lastName:       dto.lastName,
  fullName:       dto.fullName,
  role:           ((dto.role ?? '').toLowerCase() as UserRole) || UserRole.Staff,
  departmentId:   dto.departmentId ?? '',
  departmentName: dto.departmentName ?? '',
  skills:         dto.skills ?? [],
  avatar:         dto.avatar,
  isActive:       dto.isActive,
  staffId:        dto.staffId,
  phone:          dto.phone,
  createdAt:      dto.createdAt,
  updatedAt:      dto.updatedAt,
});
