/**
 * Approval service facade.
 */

import { ApprovalFilters } from '../../models/Approval';
import { UUID } from '../../models/common';
import { approvalEndpoint } from './endpoint';
import {
  ApproveApprovalRequest,
  RejectApprovalRequest,
  RequestChangesRequest,
  DelegateApprovalRequest,
  BulkApprovalRequest,
} from './requestModel';

export const approvalService = {
  getApprovals: (filters?: ApprovalFilters, page = 1, pageSize = 20) =>
    approvalEndpoint.getApprovals(filters, page, pageSize),

  getPendingApprovals: () => approvalEndpoint.getPendingApprovals(),

  getApprovalStats: () => approvalEndpoint.getApprovalStats(),

  getApprovalById: (id: UUID) => approvalEndpoint.getApprovalById(id),

  approveApproval: (req: ApproveApprovalRequest) => approvalEndpoint.approveApproval(req),

  rejectApproval: (req: RejectApprovalRequest) => approvalEndpoint.rejectApproval(req),

  requestChanges: (req: RequestChangesRequest) => approvalEndpoint.requestChanges(req),

  delegateApproval: (req: DelegateApprovalRequest) => approvalEndpoint.delegateApproval(req),

  bulkAction: (req: BulkApprovalRequest) => approvalEndpoint.bulkAction(req),
};
