/**
 * Real BFF API calls for the Forms init-data endpoint.
 * Calls GET /web-bff/api/v1/forms/init-data?formName={formName}
 */

import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import { BffFormInitDataDto } from './responseModel';
import type { FormInitData } from './model';

const mapOpts = (items: { value: string; label: string }[] | null | undefined) =>
  (items ?? []).map((o) => ({ value: o.value, label: o.label }));

// In-memory cache: keyed by formName → Promise so concurrent callers share the same request.
const _cache = new Map<string, Promise<FormInitData>>();

const _fetchInitData = async (formName: string): Promise<FormInitData> => {
  const res = await apiClient.get<BffResponse<BffFormInitDataDto>>(
    `/forms/init-data?formName=${encodeURIComponent(formName)}`,
  );
  const dto = unwrap(res);
  return {
    defaultDepartmentId:  dto.defaultDepartmentId ?? undefined,
    departments:          (dto.departments          ?? []).map((d) => ({ id: d.id, name: d.name, code: d.code })),
    ticketPriorities:     mapOpts(dto.ticketPriorities),
    ticketCategories:     mapOpts(dto.ticketCategories),
    ticketTypes:          mapOpts(dto.ticketTypes),
    ticketStatuses:       mapOpts(dto.ticketStatuses),
    taskPriorities:       mapOpts(dto.taskPriorities),
    taskStatuses:         mapOpts(dto.taskStatuses),
    assignmentStrategies: mapOpts(dto.assignmentStrategies),
    taskSkills:           mapOpts(dto.taskSkills),
    alertSeverities:      mapOpts(dto.alertSeverities),
    alertTypes:           mapOpts(dto.alertTypes),
    deadlineFilters:      mapOpts(dto.deadlineFilters),
    taskSortOrders:       mapOpts(dto.taskSortOrders),
    incidentStatuses:          mapOpts(dto.incidentStatuses),
    incidentSeverities:         mapOpts(dto.incidentSeverities),
    incidentReportTypes:        mapOpts(dto.incidentReportTypes),
    incidentCategories:         mapOpts(dto.incidentCategories),
    patientGenders:             mapOpts(dto.patientGenders),
    incidentOccurrenceStatuses: mapOpts(dto.incidentOccurrenceStatuses),
    incidentNotifyStatuses:     mapOpts(dto.incidentNotifyStatuses),
    accountRoles:               mapOpts(dto.accountRoles),
    accountStatuses:            mapOpts(dto.accountStatuses),
    accountGenders:             mapOpts(dto.accountGenders),
  };
};

export const formInitEndpoint = {
  getInitData: (formName: string): Promise<FormInitData> => {
    if (!_cache.has(formName)) {
      _cache.set(formName, _fetchInitData(formName).catch((err) => {
        // Remove from cache on error so the next call retries.
        _cache.delete(formName);
        return Promise.reject(err);
      }));
    }
    return _cache.get(formName)!;
  },
};
