import { createSlice, PayloadAction, createAsyncThunk } from '@reduxjs/toolkit';
import { Approval, ApprovalFilters, ApprovalStats, ApprovalStatus } from '../../models/Approval';
import * as approvalService from '../../services/approvalService';
import { UUID } from '../../models/common';

interface ApprovalsState {
  items: Approval[];
  pendingApprovals: Approval[];
  selectedApproval: Approval | null;
  stats: ApprovalStats | null;
  filters: ApprovalFilters;
  loading: boolean;
  error: string | null;
  actionLoading: boolean; // For approve/reject/delegate actions
  pagination: {
    page: number;
    pageSize: number;
    totalCount: number;
  };
}

const initialState: ApprovalsState = {
  items: [],
  pendingApprovals: [],
  selectedApproval: null,
  stats: null,
  filters: {
    status: ApprovalStatus.Pending,
  },
  loading: false,
  error: null,
  actionLoading: false,
  pagination: {
    page: 1,
    pageSize: 20,
    totalCount: 0,
  },
};

// Async thunks
export const fetchApprovals = createAsyncThunk(
  'approvals/fetchApprovals',
  async (
    params: { filters?: ApprovalFilters; page?: number; pageSize?: number } = {}
  ) => {
    const response = await approvalService.approvalService.getApprovals(
      params.filters,
      params.page,
      params.pageSize
    );
    return response;
  }
);

export const fetchPendingApprovals = createAsyncThunk(
  'approvals/fetchPendingApprovals',
  async () => {
    const response = await approvalService.approvalService.getPendingApprovals();
    return response;
  }
);

export const fetchApprovalStats = createAsyncThunk(
  'approvals/fetchApprovalStats',
  async () => {
    const response = await approvalService.approvalService.getApprovalStats();
    return response;
  }
);

export const fetchApprovalById = createAsyncThunk(
  'approvals/fetchApprovalById',
  async (id: UUID) => {
    const response = await approvalService.approvalService.getApprovalById(id);
    return response;
  }
);

export const approveApproval = createAsyncThunk(
  'approvals/approveApproval',
  async (request: { approvalId: UUID; note?: string }) => {
    const response = await approvalService.approvalService.approveApproval(request);
    return response;
  }
);

export const rejectApproval = createAsyncThunk(
  'approvals/rejectApproval',
  async (request: { approvalId: UUID; reason: string }) => {
    const response = await approvalService.approvalService.rejectApproval(request);
    return response;
  }
);

export const requestChanges = createAsyncThunk(
  'approvals/requestChanges',
  async (request: { approvalId: UUID; changes: string }) => {
    const response = await approvalService.approvalService.requestChanges(request);
    return response;
  }
);

export const delegateApproval = createAsyncThunk(
  'approvals/delegateApproval',
  async (request: {
    approvalId: UUID;
    delegateToId: UUID;
    delegateToName: string;
    reason: string;
    timeframe?: string;
  }) => {
    const response = await approvalService.approvalService.delegateApproval(request);
    return response;
  }
);

export const bulkApprovalAction = createAsyncThunk(
  'approvals/bulkAction',
  async (request: {
    approvalIds: UUID[];
    action: 'approve' | 'reject';
    note?: string;
    reason?: string;
  }) => {
    const response = await approvalService.approvalService.bulkAction(request);
    return response;
  }
);

// Slice
const approvalsSlice = createSlice({
  name: 'approvals',
  initialState,
  reducers: {
    setFilters: (state, action: PayloadAction<ApprovalFilters>) => {
      state.filters = action.payload;
    },
    clearFilters: (state) => {
      state.filters = { status: ApprovalStatus.Pending };
    },
    setSelectedApproval: (state, action: PayloadAction<Approval | null>) => {
      state.selectedApproval = action.payload;
    },
    clearError: (state) => {
      state.error = null;
    },
  },
  extraReducers: (builder) => {
    builder
      // Fetch approvals
      .addCase(fetchApprovals.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchApprovals.fulfilled, (state, action) => {
        state.loading = false;
        state.items = action.payload.items;
        state.pagination = {
          page: action.payload.page,
          pageSize: action.payload.pageSize,
          totalCount: action.payload.total,
        };
      })
      .addCase(fetchApprovals.rejected, (state, action) => {
        if (action.meta.aborted) return;
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch approvals';
      })
      
      // Fetch pending approvals
      .addCase(fetchPendingApprovals.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchPendingApprovals.fulfilled, (state, action) => {
        state.loading = false;
        state.pendingApprovals = action.payload;
      })
      .addCase(fetchPendingApprovals.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch pending approvals';
      })
      
      // Fetch approval stats
      .addCase(fetchApprovalStats.pending, (state) => {
        state.loading = true;
      })
      .addCase(fetchApprovalStats.fulfilled, (state, action) => {
        state.loading = false;
        state.stats = action.payload;
      })
      .addCase(fetchApprovalStats.rejected, (state, action) => {
        if (action.meta.aborted) return;
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch approval stats';
      })
      
      // Fetch approval by ID
      .addCase(fetchApprovalById.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchApprovalById.fulfilled, (state, action) => {
        state.loading = false;
        state.selectedApproval = action.payload;
      })
      .addCase(fetchApprovalById.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch approval';
      })
      
      // Approve approval
      .addCase(approveApproval.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(approveApproval.fulfilled, (state, action) => {
        state.actionLoading = false;
        // Update the approval in the list
        const index = state.items.findIndex((a) => a.id === action.payload.id);
        if (index !== -1) {
          state.items[index] = action.payload;
        }
        // Remove from pending list
        state.pendingApprovals = state.pendingApprovals.filter(
          (a) => a.id !== action.payload.id
        );
        // Update selected approval if it matches
        if (state.selectedApproval?.id === action.payload.id) {
          state.selectedApproval = action.payload;
        }
      })
      .addCase(approveApproval.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to approve approval';
      })
      
      // Reject approval
      .addCase(rejectApproval.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(rejectApproval.fulfilled, (state, action) => {
        state.actionLoading = false;
        // Update the approval in the list
        const index = state.items.findIndex((a) => a.id === action.payload.id);
        if (index !== -1) {
          state.items[index] = action.payload;
        }
        // Remove from pending list
        state.pendingApprovals = state.pendingApprovals.filter(
          (a) => a.id !== action.payload.id
        );
        // Update selected approval if it matches
        if (state.selectedApproval?.id === action.payload.id) {
          state.selectedApproval = action.payload;
        }
      })
      .addCase(rejectApproval.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to reject approval';
      })
      
      // Request changes
      .addCase(requestChanges.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(requestChanges.fulfilled, (state, action) => {
        state.actionLoading = false;
        const index = state.items.findIndex((a) => a.id === action.payload.id);
        if (index !== -1) {
          state.items[index] = action.payload;
        }
      })
      .addCase(requestChanges.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to request changes';
      })
      
      // Delegate approval
      .addCase(delegateApproval.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(delegateApproval.fulfilled, (state, action) => {
        state.actionLoading = false;
        const index = state.items.findIndex((a) => a.id === action.payload.id);
        if (index !== -1) {
          state.items[index] = action.payload;
        }
      })
      .addCase(delegateApproval.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to delegate approval';
      })
      
      // Bulk action
      .addCase(bulkApprovalAction.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(bulkApprovalAction.fulfilled, (state) => {
        state.actionLoading = false;
        // Refresh data after bulk action
      })
      .addCase(bulkApprovalAction.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to perform bulk action';
      });
  },
});

export const { setFilters, clearFilters, setSelectedApproval, clearError } =
  approvalsSlice.actions;

export default approvalsSlice.reducer;
