import React, { useState } from 'react';
import styles from '../DataCleanupPage.module.css';

const CONFIRM_PHRASE = 'XÁC NHẬN XÓA';

interface ConfirmCleanupModalProps {
  isOpen: boolean;
  totalRows: number;
  isExecuting: boolean;
  onConfirm: () => void;
  onCancel: () => void;
}

export const ConfirmCleanupModal: React.FC<ConfirmCleanupModalProps> = ({
  isOpen,
  totalRows,
  isExecuting,
  onConfirm,
  onCancel,
}) => {
  const [phrase, setPhrase] = useState('');

  if (!isOpen) return null;

  const isMatch = phrase.trim() === CONFIRM_PHRASE;

  const handleConfirm = () => {
    if (!isMatch || isExecuting) return;
    onConfirm();
  };

  const handleClose = () => {
    if (isExecuting) return;
    setPhrase('');
    onCancel();
  };

  return (
    <div className={styles.modalOverlay} onClick={handleClose}>
      <div
        className={styles.modal}
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="confirm-cleanup-title"
      >
        {/* Header */}
        <div className={styles.modalHeader}>
          <i className="fas fa-exclamation-triangle" style={{ color: 'var(--color-danger, #e53e3e)', marginRight: '8px' }} />
          <span id="confirm-cleanup-title">Xác nhận xóa dữ liệu</span>
        </div>

        {/* Body */}
        <div className={styles.modalBody}>
          <div className={styles.dangerBox}>
            <p><strong>⚠️ Hành động này không thể hoàn tác!</strong></p>
            <p>
              Bạn sắp xóa <strong>{totalRows.toLocaleString('vi-VN')}</strong> bản ghi test data
              của công ty. Dữ liệu cấu hình (tài khoản, phòng ban, quyền) sẽ được giữ nguyên.
            </p>
          </div>

          <p className={styles.confirmInstruction}>
            Để xác nhận, hãy nhập chính xác cụm từ bên dưới:
          </p>
          <p className={styles.confirmPhraseSample}>{CONFIRM_PHRASE}</p>

          <input
            type="text"
            className={`${styles.confirmInput} ${phrase && !isMatch ? styles.confirmInputError : ''}`}
            placeholder={`Nhập: ${CONFIRM_PHRASE}`}
            value={phrase}
            onChange={(e) => setPhrase(e.target.value)}
            disabled={isExecuting}
            autoFocus
          />
          {phrase && !isMatch && (
            <p className={styles.confirmInputHint}>Cụm từ không khớp</p>
          )}
        </div>

        {/* Footer */}
        <div className={styles.modalFooter}>
          <button
            className={styles.btnSecondary}
            onClick={handleClose}
            disabled={isExecuting}
          >
            Hủy
          </button>
          <button
            className={styles.btnDanger}
            onClick={handleConfirm}
            disabled={!isMatch || isExecuting}
          >
            {isExecuting ? (
              <><i className="fas fa-spinner fa-spin" /> Đang xóa...</>
            ) : (
              <><i className="fas fa-trash-alt" /> Xóa dữ liệu</>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};
