import { UUID } from './common';

export enum ApprovalType {
  TaskClosure = 'task_closure',
  TaskCreation = 'task_creation',
  TaskReassignment = 'task_reassignment',
  ResourceRequest = 'resource_request',
  SupportRequest = 'support_request',
  Other = 'other',
}

export enum ApprovalStatus {
  Pending = 'pending',
  Approved = 'approved',
  Rejected = 'rejected',
  ChangesRequested = 'changes_requested',
  Delegated = 'delegated',
}

export enum ApprovalPriority {
  Low = 'low',
  Medium = 'medium',
  High = 'high',
  Critical = 'critical',
}

export interface ApprovalChainStep {
  userId: UUID;
  userName: string;
  userRole: string;
  status: ApprovalStatus;
  decidedAt?: string;
  note?: string;
}

export interface TaskDetails {
  taskId: UUID;
  idCode: string;
  title: string;
  description: string;
  estimatedHours: number;
  actualHours?: number;
  progress: number;
  slaStatus: 'on_time' | 'at_risk' | 'overdue';
  completionNote?: string;
  assigneeId: UUID;
  assigneeName: string;
  assigneeAvatar?: string;
  assigneeRole: string;
  assigneeRating?: number;
}

export interface DelegationInfo {
  delegatedTo: UUID;
  delegatedToName: string;
  reason: string;
  timeframe?: string;
  delegatedAt: string;
}

export interface Approval {
  id: UUID;
  type: ApprovalType;
  status: ApprovalStatus;
  priority: ApprovalPriority;
  title: string;
  description: string;
  requesterId: UUID;
  requesterName: string;
  requesterRole: string;
  requesterAvatar?: string;
  approverId?: UUID;
  approverName?: string;
  requestedAt: string;
  createdAt: string;
  updatedAt: string;
  decidedAt?: string;
  decisionNote?: string;
  reason?: string;
  
  // Task-related details
  taskDetails?: TaskDetails;
  
  // Approval chain
  approvalChain?: ApprovalChainStep[];
  currentApproverLevel: number;
  totalApprovalLevels: number;
  
  // Delegation
  delegation?: DelegationInfo;
  
  // Escalation
  isEscalated: boolean;
  escalatedAt?: string;
  escalationReason?: string;
  
  // Related entities
  relatedEntityId?: UUID; // Can be task, ticket, or other entity ID
  relatedEntityType?: 'task' | 'ticket' | 'resource';
  
  // Metadata
  impactedDepartments?: string[];
  impactedUsersCount?: number;
  attachments?: string[];
  tags?: string[];
}

export interface ApprovalFilters {
  type?: ApprovalType | 'all';
  status?: ApprovalStatus | 'all';
  priority?: ApprovalPriority | 'all';
  requesterId?: UUID;
  dateFrom?: string;
  dateTo?: string;
  searchQuery?: string;
}

export interface ApprovalStats {
  pending: number;
  approvedToday: number;
  rejectedToday: number;
  approvalRate: number;
  overdue: number;
}

export interface ApproveApprovalRequest {
  approvalId: UUID;
  note?: string;
}

export interface RejectApprovalRequest {
  approvalId: UUID;
  reason: string;
}

export interface RequestChangesRequest {
  approvalId: UUID;
  changes: string;
}

export interface DelegateApprovalRequest {
  approvalId: UUID;
  delegateToId: UUID;
  delegateToName: string;
  reason: string;
  timeframe?: string;
}

export interface BulkApprovalRequest {
  approvalIds: UUID[];
  action: 'approve' | 'reject';
  note?: string;
  reason?: string;
}
