/**
 * Tabs Component with Overflow Navigation
 * Automatically shows left/right navigation arrows when tabs overflow
 */

import React, { useState, useRef, useEffect, ReactNode } from 'react';
import styles from './Tabs.module.css';

export interface Tab {
  id: string;
  label: string;
  icon?: string;
  badge?: number | string;
  badgeColor?: 'primary' | 'gray' | 'success' | 'warning' | 'danger';
  content?: ReactNode;
}

export interface TabsProps {
  tabs: Tab[];
  activeTab?: string;
  onTabChange?: (tabId: string) => void;
  variant?: 'default' | 'underline';
  className?: string;
  /** Makes the tab bar sticky to the top of its scroll container when scrolling */
  sticky?: boolean;
}

export const Tabs: React.FC<TabsProps> = ({
  tabs,
  activeTab: controlledActiveTab,
  onTabChange,
  variant = 'default',
  className = '',
  sticky = false,
}) => {
  const [internalActiveTab, setInternalActiveTab] = useState<string>(tabs[0]?.id || '');
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);
  
  const tabsRef = useRef<HTMLDivElement>(null);
  const resizeObserverRef = useRef<ResizeObserver | null>(null);

  // Use controlled or uncontrolled activeTab
  const activeTab = controlledActiveTab !== undefined ? controlledActiveTab : internalActiveTab;

  /**
   * Check if tabs overflow and update arrow visibility
   */
  const checkOverflow = () => {
    const container = tabsRef.current;
    if (!container) return;

    const hasOverflow = container.scrollWidth > container.clientWidth;

    if (hasOverflow) {
      updateArrowsVisibility();
    } else {
      setShowLeftArrow(false);
      setShowRightArrow(false);
    }
  };

  /**
   * Update arrows based on scroll position
   */
  const updateArrowsVisibility = () => {
    const container = tabsRef.current;
    if (!container) return;

    const scrollLeft = container.scrollLeft;
    const maxScroll = container.scrollWidth - container.clientWidth;

    setShowLeftArrow(scrollLeft > 5);
    setShowRightArrow(scrollLeft < maxScroll - 5);
  };

  /**
   * Scroll tabs left or right
   */
  const scrollTabs = (direction: 'left' | 'right') => {
    const container = tabsRef.current;
    if (!container) return;

    const scrollAmount = 200;
    const currentScroll = container.scrollLeft;
    const targetScroll = currentScroll + (direction === 'right' ? scrollAmount : -scrollAmount);

    container.scrollTo({
      left: targetScroll,
      behavior: 'smooth',
    });
  };

  /**
   * Scroll to make active tab visible
   */
  const scrollToTab = (tabId: string) => {
    const container = tabsRef.current;
    if (!container) return;

    const tabButton = container.querySelector(`[data-tab-id="${tabId}"]`) as HTMLElement;
    if (!tabButton) return;

    const containerRect = container.getBoundingClientRect();
    const tabRect = tabButton.getBoundingClientRect();

    // Check if tab is fully visible
    const isVisible = tabRect.left >= containerRect.left && tabRect.right <= containerRect.right;

    if (!isVisible) {
      // Scroll to center the tab
      const scrollLeft =
        tabButton.offsetLeft - container.clientWidth / 2 + tabButton.offsetWidth / 2;
      container.scrollTo({
        left: scrollLeft,
        behavior: 'smooth',
      });
    }
  };

  /**
   * Handle tab click
   */
  const handleTabClick = (tabId: string) => {
    if (controlledActiveTab === undefined) {
      setInternalActiveTab(tabId);
    }
    onTabChange?.(tabId);
    
    // Scroll to make the clicked tab visible
    setTimeout(() => scrollToTab(tabId), 50);
  };

  /**
   * Setup resize observer to detect changes
   */
  useEffect(() => {
    const container = tabsRef.current;
    if (!container) return;

    // Initial check
    checkOverflow();

    // Setup ResizeObserver
    resizeObserverRef.current = new ResizeObserver(() => {
      checkOverflow();
    });
    resizeObserverRef.current.observe(container);

    // Handle scroll events
    const handleScroll = () => updateArrowsVisibility();
    container.addEventListener('scroll', handleScroll);

    // Handle window resize
    window.addEventListener('resize', checkOverflow);

    return () => {
      resizeObserverRef.current?.disconnect();
      container.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', checkOverflow);
    };
  }, [tabs]);

  /**
   * Scroll to active tab when it changes
   */
  useEffect(() => {
    if (activeTab) {
      scrollToTab(activeTab);
    }
  }, [activeTab]);

  const hasContent = tabs.some((t) => t.content !== undefined);
  const activeContent = hasContent
    ? tabs.find((t) => t.id === activeTab)?.content
    : undefined;

  return (
    <div className={`${hasContent ? styles.tabsRoot : ''} ${className}`}>
      {/* Navigation bar */}
      <div className={`${styles.tabsContainer} ${variant === 'underline' ? styles.underlineVariant : ''} ${sticky ? styles.stickyBar : ''}`}>
        {/* Left Arrow */}
        <button
          className={`${styles.navArrow} ${styles.navArrowLeft} ${showLeftArrow ? styles.visible : ''}`}
          onClick={() => scrollTabs('left')}
          aria-label="Scroll tabs left"
          type="button"
        >
          <i className="fas fa-chevron-left"></i>
        </button>

        {/* Tabs Wrapper */}
        <div className={styles.tabsWrapper}>
          <div ref={tabsRef} className={styles.tabs}>
            {tabs.map((tab) => (
              <button
                key={tab.id}
                data-tab-id={tab.id}
                className={`${styles.tabBtn} ${activeTab === tab.id ? styles.active : ''}`}
                onClick={() => handleTabClick(tab.id)}
                type="button"
              >
                {tab.icon && <i className={tab.icon}></i>}
                <span>{tab.label}</span>
                {tab.badge !== undefined && (
                  <span
                    className={`${styles.badge} ${
                      tab.badgeColor ? styles[`badge${tab.badgeColor.charAt(0).toUpperCase()}${tab.badgeColor.slice(1)}`] : ''
                    }`}
                  >
                    {tab.badge}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Right Arrow */}
        <button
          className={`${styles.navArrow} ${styles.navArrowRight} ${showRightArrow ? styles.visible : ''}`}
          onClick={() => scrollTabs('right')}
          aria-label="Scroll tabs right"
          type="button"
        >
          <i className="fas fa-chevron-right"></i>
        </button>
      </div>

      {/* Tab Content Panel — only rendered when tabs carry content nodes */}
      {hasContent && (
        <div className={styles.tabContent}>
          {activeContent ?? null}
        </div>
      )}
    </div>
  );
};

export default Tabs;
