/**
 * SLA Alert service facade.
 */

import { SLAAlertFilters } from '../../models/SLAAlert';
import { UUID } from '../../models/common';
import { slaAlertEndpoint } from './endpoint';
import { EscalateRequest, ReassignAlertRequest } from './requestModel';

export const slaAlertService = {
  getSLAAlerts: (filters?: SLAAlertFilters, page = 1, pageSize = 50) =>
    slaAlertEndpoint.getSLAAlerts(filters, page, pageSize),

  getSLAStats: () => slaAlertEndpoint.getSLAStats(),

  getSLAAlertById: (id: UUID) => slaAlertEndpoint.getSLAAlertById(id),

  escalateAlert: (req: EscalateRequest) => slaAlertEndpoint.escalateAlert(req),

  reassignAlert: (req: ReassignAlertRequest) => slaAlertEndpoint.reassignAlert(req),

  getCandidateSuggestions: (alertId: UUID, skillsRequired?: string[]) =>
    slaAlertEndpoint.getCandidateSuggestions(alertId, skillsRequired),
};
