import React from 'react';
import type { BffCleanupPreviewDto } from '../../../services/admin/responseModel';
import styles from '../DataCleanupPage.module.css';

interface CleanupPreviewTableProps {
  preview: BffCleanupPreviewDto;
}

type PreviewRow = {
  category: string;
  label: string;
  count: number;
};

function buildRows(p: BffCleanupPreviewDto): PreviewRow[] {
  return [
    { category: 'Phiếu yêu cầu', label: 'Phiếu (Tickets)',             count: p.tickets },
    { category: 'Phiếu yêu cầu', label: 'Hoạt động phiếu',             count: p.ticketActivities },
    { category: 'Phiếu yêu cầu', label: 'Người hỗ trợ phiếu',          count: p.ticketHelpers },
    { category: 'Công việc',      label: 'Công việc (Tasks)',            count: p.tasks },
    { category: 'Công việc',      label: 'Công việc con',               count: p.taskSubtasks },
    { category: 'Công việc',      label: 'Hoạt động công việc',         count: p.taskActivities },
    { category: 'Công việc',      label: 'Người cộng tác',              count: p.taskCollaborators },
    { category: 'Tin nhắn',       label: 'Tin nhắn & Bình luận',        count: p.messages },
    { category: 'Tin nhắn',       label: 'Tệp đính kèm',               count: p.attachments },
    { category: 'Phê duyệt',      label: 'Phê duyệt',                  count: p.approvals },
    { category: 'Thống kê',       label: 'Mục tiêu cá nhân',           count: p.personalGoals },
    { category: 'Báo cáo sự cố',  label: 'Báo cáo sự cố hàng ngày',   count: p.dailyIncidentReports },
    { category: 'Báo cáo sự cố',  label: 'Sự cố y tế',                 count: p.medicalIncidents },
    { category: 'Báo cáo sự cố',  label: 'Cảnh báo té ngã',            count: p.fallLocationWarnings },
    { category: 'Cấu hình mã',    label: 'Bộ đếm mã (reset về 0)',     count: p.idCodeCounters },
  ];
}

const total = (p: BffCleanupPreviewDto) =>
  p.tickets + p.ticketActivities + p.ticketHelpers +
  p.tasks + p.taskSubtasks + p.taskActivities + p.taskCollaborators +
  p.messages + p.attachments + p.approvals + p.personalGoals +
  p.dailyIncidentReports + p.medicalIncidents + p.fallLocationWarnings +
  p.idCodeCounters;

export const CleanupPreviewTable: React.FC<CleanupPreviewTableProps> = ({ preview }) => {
  const rows = buildRows(preview);
  const totalCount = total(preview);

  return (
    <div className={styles.previewTableWrapper}>
      <table className={styles.previewTable}>
        <thead>
          <tr>
            <th>Danh mục</th>
            <th>Loại dữ liệu</th>
            <th className={styles.countCell}>Số bản ghi</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((row, i) => (
            <tr key={i} className={row.count > 0 ? styles.hasData : styles.noData}>
              <td>{row.category}</td>
              <td>{row.label}</td>
              <td className={styles.countCell}>
                {row.count > 0 ? (
                  <span className={styles.countBadge}>{row.count.toLocaleString('vi-VN')}</span>
                ) : (
                  <span className={styles.countZero}>0</span>
                )}
              </td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className={styles.totalRow}>
            <td colSpan={2}><strong>Tổng cộng</strong></td>
            <td className={styles.countCell}>
              <strong>{totalCount.toLocaleString('vi-VN')}</strong>
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
};
