/**
 * Form init-data service facade.
 *
 * Usage (in a component or Redux thunk):
 *   import { formInitService } from '@/services/formInit';
 *
 *   const data = await formInitService.getInitData('create-ticket');
 *   // data.departments  →  { id: string (Guid), name: string, code?: string }[]
 */

import { formInitEndpoint } from './endpoint';

export const formInitService = {
  /**
   * Fetch the initialisation data required to render a form.
   *
   * @param formName  Logical form identifier passed to the BFF so it can tailor
   *                  the response in future (e.g. 'create-ticket', 'create-task').
   *                  All current forms receive the same department list.
   */
  getInitData: (formName: string) => formInitEndpoint.getInitData(formName),
};

export type { FormInitData, FormOption, Department } from './model';
