/**
 * Real BFF API calls for SLA Alert endpoints.
 */

import { SLAAlert, SLAAlertFilters, SLAStats, CandidateSuggestion } from '../../models/SLAAlert';
import { PaginatedResponse, UUID } from '../../models/common';
import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import {
  BffSLAAlertDto,
  BffSLAStatsDto,
  BffSLAPagedDto,
  BffCandidateSuggestionDto,
} from './responseModel';
import {
  mapBffSLAAlert,
  mapBffSLAStats,
  mapBffSLAPaged,
  mapBffCandidateSuggestion,
} from './mapper';
import { EscalateRequest, ReassignAlertRequest } from './requestModel';

export const slaAlertEndpoint = {
  getSLAAlerts: async (
    filters?: SLAAlertFilters,
    page = 1,
    pageSize = 50
  ): Promise<PaginatedResponse<SLAAlert>> => {
    const qs = new URLSearchParams({
      page:     page.toString(),
      pageSize: pageSize.toString(),
      ...(filters?.severity    && { severity:     filters.severity }),
      ...(filters?.type        && { type:          filters.type }),
      ...(filters?.departmentId && { departmentId: filters.departmentId }),
      ...(filters?.assigneeId  && { assigneeId:   filters.assigneeId }),
      ...(filters?.searchQuery && { search:        filters.searchQuery }),
    });
    const res = await apiClient.get<BffResponse<BffSLAPagedDto>>(`/sla/alerts?${qs}`);
    return mapBffSLAPaged(unwrap(res));
  },

  getSLAStats: async (): Promise<SLAStats> => {
    const res = await apiClient.get<BffResponse<BffSLAStatsDto>>('/sla/stats');
    return mapBffSLAStats(unwrap(res));
  },

  getSLAAlertById: async (id: UUID): Promise<SLAAlert> => {
    const res = await apiClient.get<BffResponse<BffSLAAlertDto>>(`/sla/alerts/${id}`);
    return mapBffSLAAlert(unwrap(res));
  },

  escalateAlert: async (req: EscalateRequest): Promise<SLAAlert> => {
    const res = await apiClient.post<BffResponse<BffSLAAlertDto>>(
      `/sla/${req.alertId}/escalate`,
      { reason: req.reason, escalateTo: req.escalateTo }
    );
    return mapBffSLAAlert(unwrap(res));
  },

  reassignAlert: async (req: ReassignAlertRequest): Promise<void> => {
    const path =
      req.type === 'ticket'
        ? `/tickets/${req.relatedId}/reassign`
        : `/tasks/${req.relatedId}/reassign`;
    await apiClient.post(path, {
      newAssigneeId:   req.newAssigneeId,
      newAssigneeName: req.newAssigneeName,
      reason:          req.reason,
    });
  },

  getCandidateSuggestions: async (
    alertId: UUID,
    skillsRequired?: string[]
  ): Promise<CandidateSuggestion[]> => {
    const qs = new URLSearchParams({ alertId });
    if (skillsRequired?.length) qs.set('skills', skillsRequired.join(','));
    const res = await apiClient.get<BffResponse<BffCandidateSuggestionDto[]>>(
      `/users/candidates?${qs}`
    );
    return unwrap(res).map(mapBffCandidateSuggestion);
  },
};
