/**
 * Pure mapping: BFF DTO → frontend SLA model.
 */

import { SLAAlert, SLAStats, CandidateSuggestion } from '../../models/SLAAlert';
import { PaginatedResponse } from '../../models/common';
import {
  BffSLAAlertDto,
  BffSLAStatsDto,
  BffSLAPagedDto,
  BffCandidateSuggestionDto,
} from './responseModel';

export const mapBffSLAAlert = (dto: BffSLAAlertDto): SLAAlert => ({
  id:                   dto.id,
  title:                dto.title,
  relatedId:            dto.relatedId,
  relatedNumber:        dto.relatedNumber,
  type:                 dto.type as SLAAlert['type'],
  severity:             dto.severity as SLAAlert['severity'],
  priority:             'medium',           // default; BFF should provide this
  slaMinutesRemaining:  dto.slaMinutesRemaining,
  slaPercentRemaining:  0,                  // computed client-side if needed
  slaDeadline:          dto.slaDeadline,
  departmentId:         dto.departmentId,
  departmentName:       dto.departmentName,
  assigneeId:           dto.assigneeId,
  assigneeName:         dto.assigneeName,
  escalationLevel:      dto.escalationLevel ?? 0,
  escalatedAt:          dto.escalatedAt,
  createdAt:            dto.createdAt,
  lastActivityAt:       dto.updatedAt,
});

export const mapBffSLAStats = (dto: BffSLAStatsDto): SLAStats => ({
  breached:       dto.breached,
  danger:         dto.danger,
  warning:        dto.warning,
  watch:          dto.watch,
  complianceRate: dto.complianceRate ?? (
    dto.total > 0 ? Math.round(((dto.total - dto.breached) / dto.total) * 100) : 100
  ),
  totalActive:    dto.total,
});

export const mapBffSLAPaged = (dto: BffSLAPagedDto): PaginatedResponse<SLAAlert> => ({
  items:      dto.items.map(mapBffSLAAlert),
  total:      dto.total,
  page:       dto.page,
  pageSize:   dto.pageSize,
  totalPages: dto.totalPages,
});

export const mapBffCandidateSuggestion = (
  dto: BffCandidateSuggestionDto
): CandidateSuggestion => ({
  userId:            dto.userId,
  userName:          dto.userName,
  departmentName:    '',                    // BFF should provide
  currentWorkload:   dto.currentWorkload,
  skillMatch:        0,                    // BFF should provide
  availabilityScore: dto.availabilityScore,
  avgResponseTime:   0,                    // BFF should provide
});
