import { createSlice, PayloadAction, createAsyncThunk } from '@reduxjs/toolkit';
import {
  SLAAlert,
  SLAAlertFilters,
  SLAStats,
  CandidateSuggestion,
  SLASeverity,
  SLAAlertType,
} from '../../models/SLAAlert';
import * as slaAlertService from '../../services/slaAlertService';
import { UUID } from '../../models/common';

interface SLAAlertsState {
  items: SLAAlert[];
  stats: SLAStats | null;
  candidates: CandidateSuggestion[];
  selectedAlert: SLAAlert | null;
  filters: SLAAlertFilters;
  loading: boolean;
  statsLoading: boolean;
  candidatesLoading: boolean;
  actionLoading: boolean;
  error: string | null;
  pagination: {
    page: number;
    pageSize: number;
    totalCount: number;
  };
}

const initialState: SLAAlertsState = {
  items: [],
  stats: null,
  candidates: [],
  selectedAlert: null,
  filters: {
    severity: 'all',
    type: 'all',
    departmentId: 'all',
  },
  loading: false,
  statsLoading: false,
  candidatesLoading: false,
  actionLoading: false,
  error: null,
  pagination: {
    page: 1,
    pageSize: 50,
    totalCount: 0,
  },
};

// Async thunks
export const fetchSLAAlerts = createAsyncThunk(
  'slaAlerts/fetchSLAAlerts',
  async (
    params: { filters?: SLAAlertFilters; page?: number; pageSize?: number } = {}
  ) => {
    const response = await slaAlertService.slaAlertService.getSLAAlerts(
      params.filters,
      params.page,
      params.pageSize
    );
    return response;
  }
);

export const fetchSLAStats = createAsyncThunk(
  'slaAlerts/fetchSLAStats',
  async () => {
    const response = await slaAlertService.slaAlertService.getSLAStats();
    return response;
  }
);

export const fetchSLAAlertById = createAsyncThunk(
  'slaAlerts/fetchSLAAlertById',
  async (id: UUID) => {
    const response = await slaAlertService.slaAlertService.getSLAAlertById(id);
    return response;
  }
);

export const escalateAlert = createAsyncThunk(
  'slaAlerts/escalateAlert',
  async (request: { alertId: UUID; reason: string; escalateTo?: UUID }) => {
    const response = await slaAlertService.slaAlertService.escalateAlert(request);
    return response;
  }
);

export const reassignAlert = createAsyncThunk(
  'slaAlerts/reassignAlert',
  async (request: {
    alertId: UUID;
    relatedId: UUID;
    type: 'ticket' | 'task';
    newAssigneeId: UUID;
    newAssigneeName: string;
    reason: string;
  }) => {
    await slaAlertService.slaAlertService.reassignAlert({
      ...request,
      type: request.type as SLAAlertType,
    });
    return request.alertId;
  }
);

export const fetchCandidateSuggestions = createAsyncThunk(
  'slaAlerts/fetchCandidateSuggestions',
  async (params: { alertId: UUID; skillsRequired?: string[] }) => {
    const response = await slaAlertService.slaAlertService.getCandidateSuggestions(
      params.alertId,
      params.skillsRequired
    );
    return response;
  }
);

// Slice
const slaAlertsSlice = createSlice({
  name: 'slaAlerts',
  initialState,
  reducers: {
    setFilters: (state, action: PayloadAction<SLAAlertFilters>) => {
      state.filters = action.payload;
    },
    clearFilters: (state) => {
      state.filters = {
        severity: 'all',
        type: 'all',
        departmentId: 'all',
      };
    },
    setSelectedAlert: (state, action: PayloadAction<SLAAlert | null>) => {
      state.selectedAlert = action.payload;
    },
    clearError: (state) => {
      state.error = null;
    },
    // Update countdown in real-time (called by interval in component)
    updateCountdowns: (state) => {
      const now = Date.now();
      state.items.forEach((alert) => {
        const deadlineTime = new Date(alert.slaDeadline).getTime();
        const minutesRemaining = Math.floor((deadlineTime - now) / (1000 * 60));
        alert.slaMinutesRemaining = minutesRemaining;
        
        // Update severity based on time remaining
        if (minutesRemaining < 0) {
          alert.severity = SLASeverity.Breached;
        } else if (minutesRemaining < 30) {
          alert.severity = SLASeverity.Danger;
        } else if (minutesRemaining < 120) {
          alert.severity = SLASeverity.Warning;
        } else {
          alert.severity = SLASeverity.Watch;
        }
      });
    },
  },
  extraReducers: (builder) => {
    builder
      // Fetch alerts
      .addCase(fetchSLAAlerts.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchSLAAlerts.fulfilled, (state, action) => {
        state.loading = false;
        state.items = action.payload.items;
        state.pagination = {
          page: action.payload.page,
          pageSize: action.payload.pageSize,
          totalCount: action.payload.total,
        };
      })
      .addCase(fetchSLAAlerts.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch SLA alerts';
      })
      
      // Fetch stats
      .addCase(fetchSLAStats.pending, (state) => {
        state.statsLoading = true;
      })
      .addCase(fetchSLAStats.fulfilled, (state, action) => {
        state.statsLoading = false;
        state.stats = action.payload;
      })
      .addCase(fetchSLAStats.rejected, (state, action) => {
        state.statsLoading = false;
        state.error = action.error.message || 'Failed to fetch SLA stats';
      })
      
      // Fetch alert by ID
      .addCase(fetchSLAAlertById.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchSLAAlertById.fulfilled, (state, action) => {
        state.loading = false;
        state.selectedAlert = action.payload;
      })
      .addCase(fetchSLAAlertById.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to fetch SLA alert';
      })
      
      // Escalate alert
      .addCase(escalateAlert.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(escalateAlert.fulfilled, (state, action) => {
        state.actionLoading = false;
        const index = state.items.findIndex((a) => a.id === action.payload.id);
        if (index !== -1) {
          state.items[index] = action.payload;
        }
      })
      .addCase(escalateAlert.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to escalate alert';
      })
      
      // Reassign alert
      .addCase(reassignAlert.pending, (state) => {
        state.actionLoading = true;
        state.error = null;
      })
      .addCase(reassignAlert.fulfilled, (state, action) => {
        state.actionLoading = false;
        // Remove from list after successful reassignment
        state.items = state.items.filter((a) => a.id !== action.payload);
      })
      .addCase(reassignAlert.rejected, (state, action) => {
        state.actionLoading = false;
        state.error = action.error.message || 'Failed to reassign alert';
      })
      
      // Fetch candidates
      .addCase(fetchCandidateSuggestions.pending, (state) => {
        state.candidatesLoading = true;
      })
      .addCase(fetchCandidateSuggestions.fulfilled, (state, action) => {
        state.candidatesLoading = false;
        state.candidates = action.payload;
      })
      .addCase(fetchCandidateSuggestions.rejected, (state, action) => {
        state.candidatesLoading = false;
        state.error = action.error.message || 'Failed to fetch candidates';
      });
  },
});

export const { setFilters, clearFilters, setSelectedAlert, clearError, updateCountdowns } =
  slaAlertsSlice.actions;

export default slaAlertsSlice.reducer;
