import { useState, useEffect, useRef, useCallback } from 'react';
import { appSettings } from '../config/appSettings';

// ─── Types (mirrors nav MFE's UserPermissionPayload) ─────────────────────────

interface NavItemDto {
  code: string;
  path: string | null;
}

export interface AdminPermissionPayload {
  menuItemCodes: string[];
  permissionCodes: string[];
  navItems: NavItemDto[];
  issuedAt: number;
}

// ─── Shared localStorage key (same as nav MFE) ────────────────────────────────

const CACHE_KEY = 'linm:user_permissions';

function readFromCache(): AdminPermissionPayload | null {
  try {
    const raw = localStorage.getItem(CACHE_KEY);
    if (!raw) return null;
    const cached = JSON.parse(raw);
    const p = cached?.payload ?? cached;
    if (!p?.menuItemCodes || !p?.permissionCodes) return null;
    return p as AdminPermissionPayload;
  } catch {
    return null;
  }
}

async function fetchPayload(apiBase: string): Promise<AdminPermissionPayload | null> {
  const token = localStorage.getItem('auth_token');
  if (!token) return null;
  try {
    const res = await fetch(`${apiBase}/admin/users/me/permissions`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) return null;
    const json = await res.json();
    const data = json?.data ?? json;
    if (!data?.menuItemCodes) return null;
    return data as AdminPermissionPayload;
  } catch {
    return null;
  }
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

export interface UseAdminPermissionsResult {
  payload: AdminPermissionPayload | null;
  loading: boolean;
  /** True if the given path is covered by one of the user's navItems */
  hasMenuAccess: (path: string) => boolean;
  /** True if permissionCodes includes the given code */
  hasPermission: (code: string) => boolean;
  /** True if menuItemCodes includes the given menuId */
  hasMenuItem: (code: string) => boolean;
  refresh: () => void;
}

export function useAdminPermissions(): UseAdminPermissionsResult {
  const [payload, setPayload] = useState<AdminPermissionPayload | null>(() => readFromCache());
  const [loading, setLoading] = useState(payload === null);
  const mountedRef = useRef(true);
  const cancelRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const load = useCallback(async (force = false) => {
    if (!force) {
      const cached = readFromCache();
      if (cached) {
        setPayload(cached);
        setLoading(false);
        return;
      }
    }
    setLoading(true);
    const result = await fetchPayload(appSettings.apiUrl);
    if (!mountedRef.current) return;
    setPayload(result);
    setLoading(false);
  }, []);

  const refresh = useCallback(() => {
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(true); }, 0);
  }, [load]);

  useEffect(() => {
    mountedRef.current = true;
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(); }, 0);

    const onAuthChanged = () => {
      if (cancelRef.current) clearTimeout(cancelRef.current);
      cancelRef.current = setTimeout(() => { load(true); }, 0);
    };
    window.addEventListener('linm:auth:changed', onAuthChanged);
    window.addEventListener('linm:permission:changed', onAuthChanged);

    return () => {
      mountedRef.current = false;
      if (cancelRef.current) clearTimeout(cancelRef.current);
      window.removeEventListener('linm:auth:changed', onAuthChanged);
      window.removeEventListener('linm:permission:changed', onAuthChanged);
    };
  }, [load]);

  const hasMenuAccess = useCallback((path: string): boolean => {
    if (!payload) return false;
    return payload.navItems.some(
      (i) => i.path && (path === i.path || path.startsWith(i.path + '/')),
    );
  }, [payload]);

  const hasPermission = useCallback((code: string): boolean => {
    return payload?.permissionCodes.includes(code) ?? false;
  }, [payload]);

  const hasMenuItem = useCallback((code: string): boolean => {
    return payload?.menuItemCodes.includes(code) ?? false;
  }, [payload]);

  return { payload, loading, hasMenuAccess, hasPermission, hasMenuItem, refresh };
}
