import { createSlice, PayloadAction } from '@reduxjs/toolkit';
import { Ticket } from '../../models/Ticket';
import { Task } from '../../models/Task';

interface UIState {
  // Slideout states
  slideouts: {
    createTicket: boolean;
    editTicket: boolean;
    ticketDetail: boolean;
    createTask: boolean;
    editTask: boolean;
    taskDetail: boolean;
    userAssignment: boolean;
  };
  
  // Form states
  forms: {
    createTicket: Partial<Ticket>;
    editTicket: Partial<Ticket>;
    createTask: Partial<Task>;
    editTask: Partial<Task>;
  };
  
  // Toast/notification states
  toasts: Array<{
    id: string;
    message: string;
    type: 'success' | 'error' | 'warning' | 'info';
  }>;

  /**
   * Silent mode — when true, incoming notifications show only in-app
   * (bell badge / inbox badge). Toast popups are suppressed.
   * Persisted to localStorage so it survives page refresh.
   */
  silentMode: boolean;
}

const initialState: UIState = {
  slideouts: {
    createTicket: false,
    editTicket: false,
    ticketDetail: false,
    createTask: false,
    editTask: false,
    taskDetail: false,
    userAssignment: false,
  },
  forms: {
    createTicket: {},
    editTicket: {},
    createTask: {},
    editTask: {},
  },
  toasts: [],
  silentMode: localStorage.getItem('notification-silent-mode') === 'true',
};

const uiSlice = createSlice({
  name: 'ui',
  initialState,
  reducers: {
    // Slideout actions
    openSlideout: (state, action: PayloadAction<keyof UIState['slideouts']>) => {
      state.slideouts[action.payload] = true;
    },
    closeSlideout: (state, action: PayloadAction<keyof UIState['slideouts']>) => {
      state.slideouts[action.payload] = false;
    },
    closeAllSlideouts: (state) => {
      Object.keys(state.slideouts).forEach((key) => {
        state.slideouts[key as keyof UIState['slideouts']] = false;
      });
    },
    
    // Form actions
    updateCreateTicketForm: (state, action: PayloadAction<Partial<Ticket>>) => {
      state.forms.createTicket = { ...state.forms.createTicket, ...action.payload };
    },
    resetCreateTicketForm: (state) => {
      state.forms.createTicket = {};
    },
    updateEditTicketForm: (state, action: PayloadAction<Partial<Ticket>>) => {
      state.forms.editTicket = { ...state.forms.editTicket, ...action.payload };
    },
    resetEditTicketForm: (state) => {
      state.forms.editTicket = {};
    },
    updateCreateTaskForm: (state, action: PayloadAction<Partial<Task>>) => {
      state.forms.createTask = { ...state.forms.createTask, ...action.payload };
    },
    resetCreateTaskForm: (state) => {
      state.forms.createTask = {};
    },
    updateEditTaskForm: (state, action: PayloadAction<Partial<Task>>) => {
      state.forms.editTask = { ...state.forms.editTask, ...action.payload };
    },
    resetEditTaskForm: (state) => {
      state.forms.editTask = {};
    },
    
    // Toast actions
    addToast: (state, action: PayloadAction<Omit<UIState['toasts'][0], 'id'>>) => {
      state.toasts.push({
        id: Date.now().toString(),
        ...action.payload,
      });
    },
    removeToast: (state, action: PayloadAction<string>) => {
      state.toasts = state.toasts.filter((toast) => toast.id !== action.payload);
    },
    clearToasts: (state) => {
      state.toasts = [];
    },

    /** Toggle silent mode and persist the new state to localStorage. */
    toggleSilentMode: (state) => {
      state.silentMode = !state.silentMode;
      localStorage.setItem('notification-silent-mode', String(state.silentMode));
    },
  },
});

export const {
  openSlideout,
  closeSlideout,
  closeAllSlideouts,
  updateCreateTicketForm,
  resetCreateTicketForm,
  updateEditTicketForm,
  resetEditTicketForm,
  updateCreateTaskForm,
  resetCreateTaskForm,
  updateEditTaskForm,
  resetEditTaskForm,
  addToast,
  removeToast,
  clearToasts,
  toggleSilentMode,
} = uiSlice.actions;

export default uiSlice.reducer;
